var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"다녀왔습니다아......","JPN":"ただいま……","ENG":"I'm back...","TWN":"我回來了……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"후아...... 힘들었다......","JPN":"ふわぁ……疲れた……","ENG":"Phew... What a day...","TWN":"呼……好累……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"침식체 때문에 난리가 났는데 어딜 쏘다니다 이제 온 거야?","JPN":"侵食体のせいで大変なことになっていたのに、今までどこに行ってた？","ENG":"Where have you been all this time? We had to deal with all those C.O.s!","TWN":"外面被侵蝕體鬧得一團糟，妳怎麼還有心情在外面閒逛？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"헤헤, 누굴 좀 도와드리느라요.","JPN":"えへへ、人助けをしてきました。","ENG":"Heh, I was just helping someone out.","TWN":"嘿嘿，我幫人去了。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"네가 사람을 도와 줄 수도 있구나. 누군지 얼굴 한 번 보고 싶네.","JPN":"汝に人を助ける力があったのか？　誰なのか顔をみてみたい。","ENG":"Oh, I didn't know you were capable of actually helping for once. I wonder who the lucky person is.","TWN":"妳還會幫人？真想看看那人長什麼樣子。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우으...... 서빙하다 접시 깬 건 잘못했다니까요......","JPN":"うう……接客中にお皿を割ってしまったことについてはごめんなさい……","ENG":"Aw... I told you I'm sorry for breaking those plates while serving...","TWN":"呃……端盤的時候打破盤子確實是我的不對……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"졸다가 손님 머리 위에 커피 쏟은 건?","JPN":"うっかり眠ってしまってお客さんの頭にコーヒーをこぼしたことは？","ENG":"And what about spilling coffee on the customer's head while dozing off?","TWN":"那打瞌睡把咖啡撒到客人頭上的事呢？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"죄송합니다아......","JPN":"ごめんなさい……","ENG":"I'm sorry about that, too...","TWN":"對不起……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐, 됐어.","JPN":"まぁ、いい。","ENG":"Forget it.","TWN":"唉，算了。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그보다 잉그리드는? 같이 있던 거 아니었어?","JPN":"それより、イングリッドは？　一緒じゃなかったのか？","ENG":"Where's Ingrid by the way? Wasn't she with you?","TWN":"對了，英格麗呢？她不是和妳在一起嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아뇨. 잉그리드라면 이면세계에서 돌아온 뒤로 계속 자기 방에 있던데요.","JPN":"はい。イングリッドは裏世界から帰ってきて以来、ずっと自分の部屋に閉じこもってます。","ENG":"No. Ingrid's been cooped up in her room ever since we came back from the Counterside.","TWN":"沒有，英格麗從異界回來之後就一直待在自己的房裡。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그 사고뭉치가? 별일이네?","JPN":"あの問題児が？　珍しいな。","ENG":"That little rascal? Odd...","TWN":"那個搗蛋鬼沒湊熱鬧？真是奇怪。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이번에 꼭 시험을 통과하고 싶나 봐요. 바느질도 금방 배우더라고요.","JPN":"今度こそテストに合格したいみたいです。縫い物もすぐ覚えてました。","ENG":"She really seems to want to pass this test. She learned how to sew pretty quickly, too.","TWN":"她很想通過這次考試，縫紉也學得很快。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"흐음...... 가서 안 도와 줘도 돼?","JPN":"ふーん……手伝わなくていいのか？","ENG":"Hmm... You sure you don't need to go help her?","TWN":"嗯……妳不用去幫幫她？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"헤헤. 형태는 어제 밤을 꼬박 새워서 거의 다 잡았어요.","JPN":"えへへ。昨日徹夜してほとんど完成したんです。","ENG":"Heh heh. We managed to get the shape right after an all-nighter.","TWN":"嘿嘿，昨天我們熬夜做好了外型輪廓了。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그런데 마무리 작업은 꼭 혼자 하고 싶다고 해서요.","JPN":"でも、仕上げはどうしても一人でやりたいと言われたので。","ENG":"But she insisted that she finish it up by herself.","TWN":"不過收尾部分，她想自己來。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......그래, 어제 밤을 꼬박 새웠으니까 서빙할 때 그렇게 꾸벅꾸벅 졸지.","JPN":"……そうか。昨日徹夜したから、接客中にぼんやりしてたんだな。","ENG":"I see. No wonder you were dozing off all day.","TWN":"……是啊，就因為熬夜才不停地打瞌睡吧。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머. 열심히 하는 모습을 보니 정말 기대해도 되겠는걸.","JPN":"あら。頑張ってる姿を見てるとますます楽しみだわ。","ENG":"Oh, Ingrid must be working so hard! I look forward to seeing how she does on the test.","TWN":"哎呀，看她這麼認真的樣子，我還有點期待呢。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};